--     '<SCHEMA>', '<TABLE>',  '<fk_col>',
--     '<PARENT_SCHEMA>', '<PARENT_TABLE>', '<PARENT_PK>',
--     '<fk_col> should reference <parent_table>(<parent_pk>)'
-- );

-- Default values
